// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100000
#define MAX_Q 100000
// Define the structure for a tree node
typedef struct Node {
    int id;
    int parent;
    int distance;
    int sum;
    int count;
    struct Node** children;
    int numChildren;
} Node;
// Function to create a new tree node
Node* createNode(int id) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->id = id;
    node->parent = -1;
    node->distance = 0;
    node->sum = 0;
    node->count = 0;
    node->children = NULL;
    node->numChildren = 0;
    return node;
}
// Function to add a child to a node
void addChild(Node* node, Node* child) {
    node->numChildren++;
    node->children = (Node**)realloc(node->children, node->numChildren * sizeof(Node*));
    node->children[node->numChildren - 1] = child;
}
// Function to calculate the distance from the capital to each city using DFS
void dfs(Node* node, int distance) {
    node->distance = distance;
    node->sum = distance;
    node->count = 1;
    for (int i = 0; i < node->numChildren; i++) {
        dfs(node->children[i], distance + 1);
        node->sum += node->children[i]->sum;
        node->count += node->children[i]->count;
    }
}
// Function to update the distances and the dynamic programming table when a new gangster marches
void update(Node* node, int u, int dist) {
    if (node->id == u) {
        node->distance = dist;
        node->sum = dist;
        node->count = 1;
        for (int i = 0; i < node->numChildren; i++) {
            update(node->children[i], u, dist + 1);
        }
    } else {
        node->distance = dist + 1;
        node->sum = dist + 1;
    }
}
int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N;
        scanf("%d", &N);
        Node** nodes = (Node**)malloc(N * sizeof(Node*));
        for (int i = 0; i < N; i++) {
            nodes[i] = createNode(i);
        }
        for (int i = 0; i < N - 1; i++) {
            int a, b;
            scanf("%d %d", &a, &b);
            addChild(nodes[a], nodes[b]);
            addChild(nodes[b], nodes[a]);
        }
        dfs(nodes[0], 0);
        int Q;
        scanf("%d", &Q);
        for (int q = 0; q < Q; q++) {
            char type;
            int u;
            scanf(" %c %d", &type, &u);
            if (type == 'O') {
                update(nodes[0], u, 0);
            } else {
                double f = (double)nodes[u]->sum / nodes[u]->count;
                printf("%.6f\n", f);
            }
        }
        for (int i = 0; i < N; i++) {
            free(nodes[i]->children);
            free(nodes[i]);
        }
        free(nodes);
    }
    return 0;
}

