// COMPLETE, COMPILABLE Java code
import java.util.ArrayList;
import java.util.Scanner;
public class Main {
    static class Node {
        int id;
        int parent;
        int distance;
        int sum;
        int count;
        ArrayList<Node> children;
        public Node(int id) {
            this.id = id;
            this.parent = -1;
            this.distance = 0;
            this.sum = 0;
            this.count = 0;
            this.children = new ArrayList<>();
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        for (int t = 0; t < T; t++) {
            int N = sc.nextInt();
            Node[] nodes = new Node[N];
            for (int i = 0; i < N; i++) {
                nodes[i] = new Node(i);
            }
            for (int i = 0; i < N - 1; i++) {
                int a = sc.nextInt();
                int b = sc.nextInt();
                nodes[a].children.add(nodes[b]);
                nodes[b].children.add(nodes[a]);
            }
            dfs(nodes[0], 0);
            int Q = sc.nextInt();
            for (int q = 0; q < Q; q++) {
                char type = sc.next().charAt(0);
                int u = sc.nextInt();
                if (type == 'O') {
                    update(nodes[0], u, 0);
                } else {
                    double f = (double)nodes[u].sum / nodes[u].count;
                    System.out.printf("%.6f\n", f);
                }
            }
        }
    }
    public static void dfs(Node node, int distance) {
        node.distance = distance;
        node.sum = distance;
        node.count = 1;
        for (Node child : node.children) {
            dfs(child, distance + 1);
            node.sum += child.sum;
            node.count += child.count;
        }
    }
    public static void update(Node node, int u, int dist) {
        if (node.id == u) {
            node.distance = dist;
            node.sum = dist;
            node.count = 1;
            for (Node child : node.children) {
                update(child, u, dist + 1);
            }
        } else {
            node.distance = dist + 1;
            node.sum = dist + 1;
        }
    }
}

